import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Dashboard.css";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const navigate = useNavigate();

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <div className="dashboard-container">

      {/* HEADER */}
      <div className="top-bar">
        <div className="logo">
          <div className="logo-icon">C</div>
          <div>
            <h3>Campus Connect</h3>
            <p>Student Learning Hub</p>
          </div>
        </div>

        <div className="user-info">
          <div className="avatar">{user?.name?.charAt(0)}</div>
          <div>
            <p>{user?.name}</p>
            <span>{user?.role}</span>
          </div>

          <button onClick={handleLogout}>↗</button>
        </div>
      </div>

      <div className="dashboard-body">

        {/* SIDEBAR */}
        <div className="sidebar">
          <h4>Filters</h4>

          <p className="active">Recent</p>
          <p>Popular</p>

          <h5>Category</h5>
          <p className="active">All Posts</p>
          <p>Study Notes</p>
          <p>Projects</p>
          <p>Guidance</p>
          <p>Question Papers</p>
          <p>Career</p>
          <p>Skills</p>
        </div>

        {/* MAIN */}
        <div className="main-content">

          <div className="header-row">
            <div>
              <h2>All Posts</h2>
              <p>{questions.length} posts available</p>
            </div>

            <Link to="/ask" className="new-post-btn">
              + New Post
            </Link>
          </div>

          {/* POSTS */}
          {questions.map((q) => (
            <div key={q._id} className="post-card">
              
              <div className="post-header">
                <div className="avatar small">
                  {user?.name?.charAt(0)}
                </div>

                <div>
                  <h4>{user?.name}</h4>
                  <p>{user?.role}</p>
                </div>

                <span className="tag">notes</span>
              </div>

              <h3>{q.title}</h3>
              <p>{q.description}</p>

              <div className="post-footer">
                <span>❤️ 0</span>
                <span>💬 {q.answer ? 1 : 0}</span>

                <Link to={`/answers/${q._id}`}>
                  View
                </Link>
              </div>

            </div>
          ))}

        </div>
      </div>
    </div>
  );
}

export default Dashboard;
